// ==UserScript==
// @name         TradingView Screener Enhancer
// @namespace    http://tampermonkey.net/
// @version      2.0
// @description  Scrapes tickers, captures momentum, colors rows, and updates title.
// @author       You
// @match        https://www.tradingview.com/*
// @grant        none
// ==/UserScript==

(function() {
    'use strict';

    // == Configuration ==
    const TICKER_SELECTOR = '.tickerName-GrtoTeat'; // Selector for the ticker elements
    const ROW_SELECTOR = 'tr.listRow'; // Selector for table rows
    const MOMENTUM_HEADER_TEXT = 'Momentum %'; // Text to look for in header to find the correct column
    const INTERVAL_MINUTES = 3; // How often to run the scan
    const UI_UPDATE_DELAY_SECONDS = 5; // How long to wait after clicking button to allow UI to load

    /**
     * List of suffixes to remove from tickers *for the browser title display only*.
     */
    const SUFFIXES_TO_TRIM_FOR_TITLE = ['USDT.P', 'USDT'];

    // -- Calculated Constants --
    const INTERVAL_MS = INTERVAL_MINUTES * 60 * 1000;
    const UI_UPDATE_DELAY_MS = UI_UPDATE_DELAY_SECONDS * 1000;

    // == Data Storage ==
    // Expose to window so you can access it in console via `window.tickerHistory`
    window.tickerHistory = [];

    // == Functions ==

    /**
     * Helper: Cleans a ticker symbol for display purposes.
     */
    function cleanTickerForTitle(ticker) {
        for (const suffix of SUFFIXES_TO_TRIM_FOR_TITLE) {
            if (ticker.endsWith(suffix)) {
                return ticker.slice(0, -suffix.length);
            }
        }
        return ticker;
    }

    /**
     * Helper: Finds the column index for "Momentum %" dynamically.
     */
    function getMomentumColumnIndex() {
        const headers = document.querySelectorAll('thead th');
        for (let i = 0; i < headers.length; i++) {
            // Check innerText to handle potential span wrapping
            if (headers[i].innerText && headers[i].innerText.includes(MOMENTUM_HEADER_TEXT)) {
                return i;
            }
        }
        return -1;
    }

    /**
     * CORE FUNCTION: Scrapes data, Styles Rows, and prepares Title data.
     */
    function processTableData() {
        const rows = document.querySelectorAll(ROW_SELECTOR);
        if (rows.length === 0) return { tickerString: '', momentumString: '', details: [] };

        const momentumIdx = getMomentumColumnIndex();
        const processedData = [];
        const momentumValues = [];

        rows.forEach(row => {
            // 1. Get Ticker
            const tickerEl = row.querySelector(TICKER_SELECTOR);
            if (!tickerEl || !tickerEl.href) return;

            const symbolParts = tickerEl.href.split('/symbols/');
            let rawSymbol = symbolParts[symbolParts.length - 1];
            const cleanSymbol = rawSymbol.split('?')[0].replace('/', '').replace('-', ':');

            // 2. Get Momentum (Request 1)
            let momentumVal = 0;
            // Only attempt to grab momentum if we found the column
            if (momentumIdx > -1) {
                const cells = row.querySelectorAll('td');
                if (cells[momentumIdx]) {
                    // TradingView uses a special minus sign (−), replace with standard (-)
                    let rawNum = cells[momentumIdx].innerText.replace('−', '-').trim();
                    // Remove % signs if present
                    rawNum = rawNum.replace('%', '');
                    momentumVal = parseFloat(rawNum);
                    if (isNaN(momentumVal)) momentumVal = 0;
                }
            }
            momentumValues.push(`${cleanSymbol}:${momentumVal}`);

            // 3. Tag Row (Request 2) & Style Row (Request 3)
            let direction = 0;
            if (momentumVal > 0) direction = 1;
            if (momentumVal < 0) direction = -1;

            row.setAttribute('data-direction', direction);

            // Reset styles first to ensure clean slate
            row.style.backgroundColor = '';

            if (direction === 1) {
                row.style.backgroundColor = '#e6f4ea'; // Light Green (Bullish)
            } else if (direction === -1) {
                row.style.backgroundColor = '#fce8e6'; // Light Red (Bearish)
            }

            processedData.push({
                ticker: cleanSymbol,
                momentum: momentumVal,
                direction: direction
            });
        });

        return {
            // Return comma-separated string for legacy comparison logic
            tickerString: processedData.map(d => d.ticker).join(','),
            // Return comma-separated momentum values for history
            momentumString: momentumValues.join(','),
            // Return full data array for title generation
            details: processedData
        };
    }

    /**
     * Generates the Title.
     * Logic:
     * 1. If Momentum data exists (and isn't all 0), show Bulls (↑) vs Bears (↓).
     * 2. If NO Momentum data (or column missing), Fallback to Master_v1 logic (Show newly added count).
     */
    function updatePageTitle(data, newlyAddedArray, totalCount) {
        // Separate Bulls and Bears
        const bulls = data.filter(d => d.direction === 1);
        const bears = data.filter(d => d.direction === -1);

        // == STRATEGY 1: NEW FEATURE (Momentum Found) ==
        if (bulls.length > 0 || bears.length > 0) {
            // Sort: Bulls (High to Low), Bears (Low to High - most negative first)
            bulls.sort((a, b) => b.momentum - a.momentum);
            bears.sort((a, b) => a.momentum - b.momentum);

            const bullNames = bulls.map(d => cleanTickerForTitle(d.ticker));
            const bearNames = bears.map(d => cleanTickerForTitle(d.ticker));

            let titleParts = [];
            if (bulls.length > 0) titleParts.push(`↑(${bulls.length}): ${bullNames.join(', ')}`);
            if (bears.length > 0) titleParts.push(`↓(${bears.length}): ${bearNames.join(', ')}`);

            document.title = titleParts.join(' | ');
            return { bullCount: bulls.length, bearCount: bears.length };
        }

        // == STRATEGY 2: FALLBACK (Master_v1 Logic) ==
        // This runs if Momentum column is missing or all values are 0
        let newTitle;
        if (newlyAddedArray.length > 0) {
            const cleanedDisplayList = newlyAddedArray.map(cleanTickerForTitle);
            newTitle = `(${totalCount}) +${newlyAddedArray.length}: ${cleanedDisplayList.join(', ')}`;
        } else {
            newTitle = `(${totalCount}) No New Tickers`;
        }

        document.title = newTitle;
        return { bullCount: 0, bearCount: 0 };
    }

    /**
     * Tries to find the button using a series of strategies.
     */
    function findScanButton() {
        const complexButtonSelector = ".apply-common-tooltip[class*='withStartSlot'][class*='lightButton'][class*='noContent'][class*='secondary']:not([data-name])";

        let button = document.querySelector('[data-name="pine-screener-scan-btn"]');
        if (button) return button;

        const stableAncestor = document.querySelector('[class*="columnSetPanelWrapper"]');
        if (stableAncestor) {
            button = stableAncestor.querySelector(complexButtonSelector);
            if (button) return button;
        }

        button = document.querySelector(complexButtonSelector);
        if (button) return button;

        return null;
    }

    /**
     * Polls the DOM until the button is found.
     */
    function waitForButton(callback) {
        const maxWaitTime = 10000; // 10 seconds
        const pollInterval = 200; // Check every 200ms
        let elapsedTime = 0;

        const intervalId = setInterval(() => {
            const button = findScanButton();
            if (button) {
                clearInterval(intervalId);
                callback(button);
            } else {
                elapsedTime += pollInterval;
                if (elapsedTime >= maxWaitTime) {
                    clearInterval(intervalId);
                    console.error(`[${new Date().toLocaleTimeString()}] Scan button not found.`);
                }
            }
        }, pollInterval);
    }

    /**
     * Main Execution Logic
     */
    function scanAndLog() {
        const currentTime = new Date();
        console.log(`[${currentTime.toLocaleTimeString()}] Starting new scan cycle...`);

        waitForButton((button) => {
            button.click();
            console.log(`Scan button clicked. Waiting ${UI_UPDATE_DELAY_SECONDS}s for results...`);

            setTimeout(() => {
                // 1. Process Rows (Extract, Tag, Style)
                const scanResult = processTableData();
                const currentTickersString = scanResult.tickerString;
                const currentTimestamp = new Date();
                const currentTickersArray = currentTickersString ? currentTickersString.split(',') : [];

                // 2. Compare with previous run
                const lastRun = window.tickerHistory.length > 0 ? window.tickerHistory[window.tickerHistory.length - 1] : null;
                const previousTickerSet = lastRun && lastRun.tickers ? new Set(lastRun.tickers.split(',')) : new Set();

                const newlyAdded = currentTickersArray.filter(ticker => !previousTickerSet.has(ticker));
                const removed = lastRun && lastRun.tickers ? lastRun.tickers.split(',').filter(ticker => !!ticker && !new Set(currentTickersArray).has(ticker)) : [];

                // 3. Update Title (Pass newlyAdded for fallback support)
                const counts = updatePageTitle(scanResult.details, newlyAdded, currentTickersArray.length);

                // 4. Store Result
                window.tickerHistory.push({
                    timestamp: currentTimestamp.toLocaleString(),
                    tickers: currentTickersString,
                    momentumValues: scanResult.momentumString, // New Data
                    count: currentTickersArray.length,
                    bullBearSplit: `Bull:${counts.bullCount}/Bear:${counts.bearCount}`, // New Data
                    newlyAdded: newlyAdded.join(','),
                    removed: removed.join(',')
                });

                // 5. Log summary
                console.log(`Tab title updated to: "${document.title}"`);
                if (newlyAdded.length > 0) console.log(`%c[NEW] ${newlyAdded.join(', ')}`, 'color: green;');
                if (removed.length > 0) console.log(`%c[REMOVED] ${removed.join(', ')}`, 'color: red;');

                console.log(`History updated. Total entries: ${window.tickerHistory.length}.`);
                console.table(window.tickerHistory);

            }, UI_UPDATE_DELAY_MS);
        });
    }

    // == Script Initialization ==

    console.log('Enhanced Script initialized. Running first scan now...');
    scanAndLog();

    // Expose the interval ID so it can be cleared from console if needed
    window.scanIntervalId = setInterval(scanAndLog, INTERVAL_MS);

    console.log(`Script is running. A new scan will occur every ${INTERVAL_MINUTES} minutes.`);
    console.log('Access history via: window.tickerHistory');
    console.log('Stop script via: clearInterval(window.scanIntervalId)');

})();
