// 1. Select elements using standard JS (replacing $$)
// We use a generic attribute selector so it doesn't break when class names change
const links = document.querySelectorAll('a[href*="/symbols/"]');

// 2. Process the data
const result = Array.from(links)
  .filter(a => a.href.includes('?exchange=')) // Ensure it is a valid ticker link
  .map(a => {
    try {
      const urlObj = new URL(a.href);

      // Extract Symbol (remove '/symbols/' and extra slashes)
      const pathParts = urlObj.pathname.split('/symbols/');
      const symbol = pathParts[1] ? pathParts[1].replace(/\//g, '') : '';

      // Extract Exchange from query parameters
      const exchange = urlObj.searchParams.get('exchange');

      if (exchange && symbol) {
        return `${exchange}:${symbol}`;
      }
    } catch (e) {
      return null;
    }
  })
  .filter(item => item !== null && item !== undefined) // Remove errors
  .filter((value, index, self) => self.indexOf(value) === index); // Remove duplicates

// 3. Join with commas
const finalString = result.join(',');

// 4. Write to Clipboard using standard API (replacing copy())
navigator.clipboard.writeText(finalString)
  .then(() => {
    console.log('Automa: Copied tickers to clipboard!');
  })
  .catch(err => {
    console.error('Automa: Failed to copy text: ', err);
  });

// 5. Return the value (Optional: saves it to the workflow's 'result' variable)
return finalString;
